external_knowledge:
; The access property with ID 1 is assumed to be the root in the permission hierarchy; 
; The ratio of unique users to access count is calculated as a measure of permission usage efficiency; 
; The results are ordered to prioritize permissions with higher levels in the hierarchy and usage.

sql:
SELECT COUNT(permission_id) AS permission_grant_count
FROM application_permissions
WHERE permission_id = 1;

SELECT permission_id, created_at
FROM permissions
ORDER BY created_at DESC;
